import{_ as e,o as r,c as h,ah as d}from"./chunks/framework.BNo2o5Ln.js";const D=JSON.parse('{"title":"UDP 协议","description":"","frontmatter":{"title":"UDP 协议","order":3},"headers":[],"relativePath":"server/network/basic/udp.md","filePath":"server/network/basic/udp.md"}'),i={name:"server/network/basic/udp.md"};function P(l,a,p,n,t,o){return r(),h("div",null,[...a[0]||(a[0]=[d('<h1 id="udp-协议" tabindex="-1">UDP 协议 <a class="header-anchor" href="#udp-协议" aria-label="Permalink to “UDP 协议”">​</a></h1><p>UDP（User Datagram Protocol，用户数据报协议）是无连接的、不可靠的传输层协议。UDP 不提供连接建立、数据确认、重传机制，只负责尽最大努力交付数据。</p><h2 id="udp-vs-tcp" tabindex="-1">UDP vs TCP <a class="header-anchor" href="#udp-vs-tcp" aria-label="Permalink to “UDP vs TCP”">​</a></h2><h3 id="udp-的优势" tabindex="-1">UDP 的优势 <a class="header-anchor" href="#udp-的优势" aria-label="Permalink to “UDP 的优势”">​</a></h3><p>无连接：不需要三次握手，发送数据前不需要建立连接，开销小。</p><p>首部开销小：UDP 首部只有 8 字节，TCP 首部最小 20 字节。</p><p>无拥塞控制：网络拥塞时不降低发送速率，适合实时应用（如视频会议、在线游戏）。</p><p>支持一对一、一对多、多对多：支持单播、广播、组播。</p><h3 id="udp-的劣势" tabindex="-1">UDP 的劣势 <a class="header-anchor" href="#udp-的劣势" aria-label="Permalink to “UDP 的劣势”">​</a></h3><p>不可靠：不保证数据到达，数据可能丢失、重复、乱序。</p><p>无流量控制：发送方不知道接收方的接收能力，可能淹没接收方。</p><p>无拥塞控制：网络拥塞时不降低发送速率，可能导致网络瘫痪。</p><h2 id="udp-头部格式" tabindex="-1">UDP 头部格式 <a class="header-anchor" href="#udp-头部格式" aria-label="Permalink to “UDP 头部格式”">​</a></h2><h3 id="源端口和目的端口" tabindex="-1">源端口和目的端口 <a class="header-anchor" href="#源端口和目的端口" aria-label="Permalink to “源端口和目的端口”">​</a></h3><p>16 位，标识发送方和接收方的进程。端口为 0 表示不指定端口。</p><h3 id="长度" tabindex="-1">长度 <a class="header-anchor" href="#长度" aria-label="Permalink to “长度”">​</a></h3><p>16 位，UDP 首部和数据的总长度，以字节为单位。最小值 8（只有首部）。</p><h3 id="校验和" tabindex="-1">校验和 <a class="header-anchor" href="#校验和" aria-label="Permalink to “校验和”">​</a></h3><p>16 位，检验 UDP 首部和数据的完整性。UDP 的校验和是可选的，TCP 的校验和是必须的。</p><h2 id="udp-的应用场景" tabindex="-1">UDP 的应用场景 <a class="header-anchor" href="#udp-的应用场景" aria-label="Permalink to “UDP 的应用场景”">​</a></h2><h3 id="dns" tabindex="-1">DNS <a class="header-anchor" href="#dns" aria-label="Permalink to “DNS”">​</a></h3><p>DNS 使用 UDP 通信，查询和响应短小，UDP 的开销小。DNS 响应超过 512 字节时使用 TCP。</p><h3 id="dhcp" tabindex="-1">DHCP <a class="header-anchor" href="#dhcp" aria-label="Permalink to “DHCP”">​</a></h3><p>DHCP 使用 UDP 通信，客户端广播发送 DHCP Discover，服务器广播回复 DHCP Offer。</p><h3 id="voip" tabindex="-1">VoIP <a class="header-anchor" href="#voip" aria-label="Permalink to “VoIP”">​</a></h3><p>VoIP（Voice over IP）使用 UDP 传输语音数据，容忍少量丢包，但要求低延迟。重传会导致延迟增加，影响通话质量。</p><h3 id="在线游戏" tabindex="-1">在线游戏 <a class="header-anchor" href="#在线游戏" aria-label="Permalink to “在线游戏”">​</a></h3><p>在线游戏使用 UDP 传输游戏状态，容忍少量丢包，但要求低延迟。游戏客户端预测和插值可以补偿丢包。</p><h3 id="直播" tabindex="-1">直播 <a class="header-anchor" href="#直播" aria-label="Permalink to “直播”">​</a></h3><p>直播使用 UDP 传输视频数据，容忍少量丢包，但要求低延迟。重传会导致延迟增加，影响观看体验。</p><h2 id="udp-的增强" tabindex="-1">UDP 的增强 <a class="header-anchor" href="#udp-的增强" aria-label="Permalink to “UDP 的增强”">​</a></h2><h3 id="可靠-udp" tabindex="-1">可靠 UDP <a class="header-anchor" href="#可靠-udp" aria-label="Permalink to “可靠 UDP”">​</a></h3><p>可靠 UDP 在 UDP 之上增加序列号、确认应答、超时重传，实现可靠传输。可靠 UDP 用于游戏、直播等场景，比 TCP 更灵活。</p><p>KCP（快速可靠传输 ARQ）是可靠 UDP 的实现，比 TCP 延迟低 30%-40%，但吞吐量比 TCP 低 10%-20%。</p><h3 id="udp-转发" tabindex="-1">UDP 转发 <a class="header-anchor" href="#udp-转发" aria-label="Permalink to “UDP 转发”">​</a></h3><p>UDP 转发（UDP Forwarding）是将 UDP 报文转发到其他服务器，实现负载均衡。UDP 转发需要修改源端口和目的端口，重新计算校验和。</p><h3 id="udp-打洞" tabindex="-1">UDP 打洞 <a class="header-anchor" href="#udp-打洞" aria-label="Permalink to “UDP 打洞”">​</a></h3><p>UDP 打洞（UDP Hole Punching）是 NAT 穿透技术，用于 P2P 通信。两个 NAT 后的客户端通过中间服务器交换公网 IP 和端口，然后直接通信。</p><h2 id="udp-的安全问题" tabindex="-1">UDP 的安全问题 <a class="header-anchor" href="#udp-的安全问题" aria-label="Permalink to “UDP 的安全问题”">​</a></h2><h3 id="udp-放大攻击" tabindex="-1">UDP 放大攻击 <a class="header-anchor" href="#udp-放大攻击" aria-label="Permalink to “UDP 放大攻击”">​</a></h3><p>攻击者伪造源 IP，向 DNS、NTP 等服务器发送小请求，服务器回复大响应，流量被放大，攻击目标。解决方案：限制响应大小、验证请求来源。</p><h3 id="udp-洪水攻击" tabindex="-1">UDP 洪水攻击 <a class="header-anchor" href="#udp-洪水攻击" aria-label="Permalink to “UDP 洪水攻击”">​</a></h3><p>攻击者向目标发送大量 UDP 报文，耗尽目标的带宽和处理能力。解决方案：限流、黑名单、DDoS 防护。</p><h2 id="udp-的编程注意事项" tabindex="-1">UDP 的编程注意事项 <a class="header-anchor" href="#udp-的编程注意事项" aria-label="Permalink to “UDP 的编程注意事项”">​</a></h2><h3 id="报文大小" tabindex="-1">报文大小 <a class="header-anchor" href="#报文大小" aria-label="Permalink to “报文大小”">​</a></h3><p>UDP 报文最大 65507 字节（65535 - 8 字节首部 - 20 字节 IP 首部）。超过 MTU（1500 字节）的报文会被 IP 层分片，分片丢失会导致整个报文丢失。建议 UDP 报文不超过 1472 字节（1500 - 20 字节 IP 首部 - 8 字节 UDP 首部）。</p><h3 id="缓冲区溢出" tabindex="-1">缓冲区溢出 <a class="header-anchor" href="#缓冲区溢出" aria-label="Permalink to “缓冲区溢出”">​</a></h3><p>UDP 不保证数据到达，发送速率超过接收方的处理能力时，接收方的缓冲区溢出，数据丢失。解决方案：增加缓冲区、限流、丢包策略。</p><h3 id="校验和-1" tabindex="-1">校验和 <a class="header-anchor" href="#校验和-1" aria-label="Permalink to “校验和”">​</a></h3><p>UDP 的校验和是可选的，设置为 0 表示不计算校验和。建议启用校验和，避免数据损坏。</p><p>UDP 是简单高效的传输协议，适合实时应用和短连接场景。理解 UDP 的原理和权衡，有助于选择合适的传输协议。</p>',51)])])}const c=e(i,[["render",P]]);export{D as __pageData,c as default};
